fun markdownToAsciiDoc(markdown: String): String {
    val headingPattern = Regex("^(#{1,6})\\s+(.*)$")
    val numberedListPattern = Regex("^\\d+\\.\\s+.*$")
    val output = StringBuilder()
    var insideCodeBlock = false

    markdown.lineSequence().forEach { line ->
        val trimmed = line.trimStart()

        if (trimmed.startsWith("```")) {
            if (!insideCodeBlock) {
                val language = trimmed.removePrefix("```").trim()
                if (language.isNotEmpty()) {
                    output.append("[source,").append(language).append("]\n")
                }
                output.append("----\n")
                insideCodeBlock = true
            } else {
                output.append("----\n")
                insideCodeBlock = false
            }
            return@forEach
        }

        if (insideCodeBlock) {
            output.append(line).append("\n")
            return@forEach
        }

        val headingMatch = headingPattern.find(line)
        if (headingMatch != null) {
            val level = headingMatch.groupValues[1].length
            val title = headingMatch.groupValues[2]
            output.append("=".repeat(level)).append(" ").append(title).append("\n")
            return@forEach
        }

        if (trimmed.startsWith("- ")) {
            output.append(line.replaceFirst("- ", "* ")).append("\n")
            return@forEach
        }

        if (numberedListPattern.matches(trimmed)) {
            output.append(line).append("\n")
            return@forEach
        }

        output.append(line).append("\n")
    }

    if (insideCodeBlock) {
        output.append("----\n")
    }

    return output.toString()
}

tasks.register("prepareAsciiDoc") {
    group = "documentation"
    description = "Konwertuje pliki Markdown z doc/ do AsciiDoc w build/docs/asciidoc"

    val sourceDir = layout.projectDirectory.dir("doc")
    val outputDir = layout.buildDirectory.dir("docs/asciidoc")

    inputs.dir(sourceDir)
    outputs.dir(outputDir)

    doLast {
        val sourceRoot = sourceDir.asFile
        val targetRoot = outputDir.get().asFile
        targetRoot.deleteRecursively()
        targetRoot.mkdirs()

        sourceRoot.walkTopDown()
            .filter { it.isFile && it.extension.lowercase() == "md" }
            .forEach { mdFile ->
                val relativePath = mdFile.relativeTo(sourceRoot).invariantSeparatorsPath
                val adocPath = relativePath.removeSuffix(".md") + ".adoc"
                val adocFile = targetRoot.resolve(adocPath)
                adocFile.parentFile.mkdirs()
                adocFile.writeText(markdownToAsciiDoc(mdFile.readText()))
            }
    }
}

tasks.register("docsPdf") {
    group = "documentation"
    description = "Generuje PDF z dokumentacji Markdown przez asciidoc2pdf"
    dependsOn("prepareAsciiDoc")

    doLast {
        val checkCommand = exec {
            commandLine("bash", "-lc", "command -v asciidoc2pdf >/dev/null 2>&1")
            isIgnoreExitValue = true
        }

        if (checkCommand.exitValue != 0) {
            throw GradleException(
                "Nie znaleziono 'asciidoc2pdf'. Zainstaluj narzedzie (np. pakiet asciidoc3) i uruchom zadanie ponownie."
            )
        }

        val adocRoot = layout.buildDirectory.dir("docs/asciidoc").get().asFile
        val pdfRoot = layout.buildDirectory.dir("docs/pdf").get().asFile
        pdfRoot.deleteRecursively()
        pdfRoot.mkdirs()

        adocRoot.walkTopDown()
            .filter { it.isFile && it.extension.lowercase() == "adoc" }
            .forEach { adocFile ->
                val relativeParent = adocFile.parentFile.relativeTo(adocRoot).invariantSeparatorsPath
                val targetDir = if (relativeParent == ".") pdfRoot else pdfRoot.resolve(relativeParent)
                targetDir.mkdirs()

                exec {
                    commandLine("asciidoc2pdf", "-D", targetDir.absolutePath, adocFile.absolutePath)
                }
            }
    }
}

